const hostData = {};

for (const item of $input.all()) {
  const data = item.json;

  if (data.result && Array.isArray(data.result) && data.result.length > 0 && data.result[0].hosts) {
    for (const res of data.result) {
      const hostInfo = res.hosts[0];
      const hostname = hostInfo.name;

      if (!hostData[hostname]) {
        hostData[hostname] = {
          hostname: hostname,
          hostid: hostInfo.hostid,
          cpu: "-",
          ram: "-",
          disk: "-",
          problems: [],
          logs: ["Aucune erreur détectée dans les logs."]
        };
      }

      const val = res.lastvalue;
      const key = res.key_;

      if (key === 'system.cpu.util' || key === 'proxmox.node.cpu[proxmox]') {
        hostData[hostname].cpu = parseFloat(val).toFixed(2) + ' %';
      } else if (key === 'vm.memory.utilization' || key === 'proxmox.node.mempourcent[proxmox]') {
        hostData[hostname].ram = parseFloat(val).toFixed(2) + ' %';
      } else if (key === 'vfs.fs.dependent.size[/,pused]' || key === 'proxmox.node.percent[proxmox,local-lvm]') {
        hostData[hostname].disk = parseFloat(val).toFixed(2) + ' %';
      }

      if (res.triggerid && res.value === "1") {
        const severityMap = { 0: 'NC', 1: 'Info', 2: 'Avert.', 3: 'Moyen', 4: 'Haut', 5: 'Critique' };
        hostData[hostname].problems.push({
          description: res.description,
          priorite: severityMap[res.priority] || res.priority
        });
      }
    }
  }

  if (data.status === "success" && data.data && data.data.result) {
    const logsFound = data.data.result;
    if (logsFound.length > 0) {
      logsFound.forEach(streamObj => {
        const hostname = streamObj.stream.host || "Unknown";
        if (hostData[hostname]) {
          const messages = streamObj.values.map(v => v[1].trim());
          if (hostData[hostname].logs[0] === "Aucune erreur détectée dans les logs.") {
            hostData[hostname].logs = [];
          }
          hostData[hostname].logs = [...hostData[hostname].logs, ...messages].slice(-10);
        }
      });
    }
  }
}

return Object.values(hostData).map(h => ({ json: h }));

const llmResponse = $input.first().json;
let reportText = llmResponse.output || llmResponse.text || llmResponse.response || (typeof llmResponse === 'string' ? llmResponse : '');

function getSection(text, startTitle, endTitle) {
    const start = text.indexOf(startTitle);
    const end = endTitle ? text.indexOf(endTitle) : text.length;
    if (start === -1) return '';
    return text.substring(start + startTitle.length, end).trim();
}

const alertes = getSection(reportText, "### 🔴 ALERTES PRIORITAIRES :", "### 🟡 ANALYSE DES SERVICES :");
const services = getSection(reportText, "### 🟡 ANALYSE DES SERVICES :", "### 📊 PERFORMANCE :");
const perf = getSection(reportText, "### 📊 PERFORMANCE :", "### 🛠 PLAN D'ACTION :");
const actions = getSection(reportText, "### 🛠 PLAN D'ACTION :", null);

const clean = (txt) => txt.replace(/\*\*/g, '').replace(/^\d+\.\s/gm, '');

const actionLines = clean(actions).split('\n').map(l => l.trim()).filter(l => l.length > 5);
let actionListHtml = '';
let currentActionIndex = 0;

actionLines.forEach((line) => {
    if (line.includes("(3 recommandations")) return;
    const isNewBlock = (!line.startsWith('•') && !line.startsWith('-') && !line.startsWith('*')) || line.includes(' :');
    if (isNewBlock && currentActionIndex < 3) {
        currentActionIndex++;
        if (currentActionIndex > 1) actionListHtml += '</div></div>';
        actionListHtml += `<div class="action-item"><div class="action-num">${currentActionIndex}</div><div class="action-text"><strong style="color:#fff; display:block; margin-bottom:10px; font-size:16px; letter-spacing:0.5px;">${line.replace(':', '')}</strong>`;
    } else {
        const cleanDetail = line.replace(/^[•\-*]\s?/, '');
        actionListHtml += `<div style="margin-top:10px; font-size:14px; opacity:0.8; padding-left:15px; border-left:1px solid #334155; line-height:1.6;">${cleanDetail}</div>`;
    }
});
actionListHtml += '</div></div>';

const htmlContent = `<!DOCTYPE html>
<html lang="fr">
<head>
<meta charset="UTF-8">
<link href="https://fonts.googleapis.com/css2?family=Plus+Jakarta+Sans:wght@400;600;800&family=JetBrains+Mono&display=swap" rel="stylesheet">
<style>
:root { --bg:#080a0f; --card:#11151c; --border:#1e2530; --red:#ff5f57; --orange:#ffbd2e; --blue:#2bc1ff; --green:#28c840; --text:#c9d1d9; --text-dim:#8b949e; }
body { font-family:'Plus Jakarta Sans',sans-serif; background:var(--bg); color:var(--text); padding:50px 20px; margin:0; line-height:1.8; }
.wrapper { max-width:950px; margin:auto; }
.header { border-left:4px solid var(--blue); padding-left:20px; margin-bottom:60px; }
.header h1 { margin:0; font-weight:800; font-size:28px; letter-spacing:-1px; color:#fff; text-transform:uppercase; }
.header span { font-family:'JetBrains Mono'; font-size:11px; color:var(--blue); opacity:0.8; letter-spacing:1px; }
.section-label { font-size:11px; font-weight:800; text-transform:uppercase; letter-spacing:2px; margin:60px 0 25px; display:flex; align-items:center; }
.section-label::after { content:''; flex:1; height:1px; background:var(--border); margin-left:15px; }
.card { background:var(--card); border:1px solid var(--border); border-radius:14px; padding:35px; margin-bottom:40px; box-shadow:0 12px 40px rgba(0,0,0,0.4); }
.alert-box { border-left:4px solid var(--red); background:rgba(255,95,87,0.08); padding:25px; border-radius:0 10px 10px 0; color:var(--text); font-size:15px; }
.perf-grid { display:grid; grid-template-columns:repeat(auto-fit,minmax(280px,1fr)); gap:30px; margin-bottom:50px; }
.perf-item { background:var(--card); border:1px solid var(--border); padding:30px; border-radius:16px; }
.perf-item h4 { margin:0 0 25px 0; color:var(--blue); font-size:13px; letter-spacing:1.5px; text-transform:uppercase; padding-bottom:12px; border-bottom:1px solid var(--border); }
.metric-row { display:flex; justify-content:space-between; font-size:14px; margin-bottom:15px; align-items:center; }
.metric-val { color:#fff; font-weight:600; font-family:'JetBrains Mono'; background:rgba(43,193,255,0.1); border:1px solid rgba(43,193,255,0.2); padding:3px 10px; border-radius:6px; font-size:13px; }
.action-item { display:flex; gap:25px; margin-bottom:35px; align-items:flex-start; padding:30px; background:rgba(255,255,255,0.02); border:1px solid var(--border); border-radius:14px; }
.action-num { background:var(--green); color:#000; min-width:30px; height:30px; border-radius:50%; display:flex; align-items:center; justify-content:center; font-weight:800; font-size:14px; }
.action-text { flex:1; }
.service-text { color:var(--text-dim); font-size:15px; white-space:pre-wrap; line-height:1.9; }
</style>
</head>
<body>
<div class="wrapper">
<div class="header"><h1>Intelligence Système</h1><span>// LAB_MONITORING // RAPPORT_24H_ANALYSIS</span></div>
<div class="section-label" style="color:var(--red)">Alertes Critiques</div>
<div class="card"><div class="alert-box">${clean(alertes).split('\n').filter(l=>l.trim().length>0).join('<br><br>')}</div></div>
<div class="section-label" style="color:var(--orange)">Analyse des Services</div>
<div class="card"><div class="service-text">${clean(services).split('\n').filter(l=>l.trim().length>0).join('<br><br>')}</div></div>
<div class="section-label" style="color:var(--blue)">Métriques de Performance</div>
<div class="perf-grid" id="perf-dynamic"></div>
<div class="section-label" style="color:var(--green)">Plan d'Action Tactique</div>
<div>${actionListHtml}</div>
<div style="text-align:center; font-size:10px; color:#484f58; margin-top:100px; font-family:'JetBrains Mono'; letter-spacing:2px; opacity:0.6;">SRE_AUTOMATION_NODE_V3 // TERMINAL_ID: ${Math.random().toString(36).substr(2,8).toUpperCase()}</div>
</div>
</body>
</html>`;

return [{ json: { report_html: htmlContent } }];
